# Lance une session Claude Code headless qui execute la routine de trading.
# Tourne en LOCAL -> acces complet : repo, config/.env (cles Bybit), skills node, MCP screener.
# Usage : powershell -File routines\run-routine.ps1            (auto / planifie)
#         powershell -File routines\run-routine.ps1 -Manual    (manuel : test ou trade delibere par the maintainer)
param([switch]$Manual)
# NOTE: the edge values, R-multiples and findings embedded in the prompt below are
# ILLUSTRATIVE defaults from the author's demo runs (overfit). Re-validate OOS before
# trusting them. See DISCLAIMER.md.
$ErrorActionPreference = "Stop"
$proj = Split-Path -Parent $PSScriptRoot
Set-Location $proj
New-Item -ItemType Directory -Force -Path "$proj\routines\logs" | Out-Null
$src = if ($Manual) { "manuel" } else { "auto" }
$ts  = Get-Date -Format "yyyy-MM-dd_HH-mm"
$log = "$proj\routines\logs\routine_${ts}_${src}.log"

$prompt = "Execute la routine de trading COMPLETE definie dans routines/trade-routine.md. Lis d'abord trade-journal/LESSONS.md + JOURNAL.md + tradingview/STRATEGY_MATRIX.md + tradingview/DESKTOP_INDICATORS.md + tradingview/ZEIIERMAN_ZONES.md. Etapes OBLIGATOIRES dans l'ordre: (0) DATE: 'node trade-journal/journal.js today' (jamais d'autre source de date). (1) PREAMBULE: reconcile + risk (circuit breaker: halt:true => AUCUN nouveau trade) + exposure, puis gerer les positions/pending existants (cancel stale, trail SL, scale-in si gagnant). GESTION DES PENDINGS (2 regles anti no-trade): (a) ENTREE-REBOND RATEE (lecon Short A): si un pending short-du-rebond (limit AU-DESSUS du prix) ou long-du-creux (limit SOUS le prix) n'est PAS rempli ET que le prix a fui >2xATR (~3%) DANS LE SENS DU TRADE (le rebond attendu n'est pas venu) -> l'approche d'entree a ECHOUE: REPOSITIONNER en CONTINUATION (entree proche du prix, SL au-dela de la structure) si la tendance tient, OU ANNULER pour liberer le slot. Ne jamais rester spectateur d'un move gagnant qu'on rate. (b) PRUNING DE PENDING (slot sous pression): un pending ne risque AUCUN capital -> l'annuler est GRATUIT (different de la rotation qui ferme un gagnant ouvert). Si slots/cap pleins ET un candidat du scan MEME SENS score nettement mieux (>=1.3x score effectif) qu'un pending au repos -> ANNULER le pending faible et prendre le meilleur. Documenter (review pending annule + rationale nouveau). SUIVI QUALITATIF (Imp1/2/3): AVANT de statuer chaque trade open/pending, LIRE son brief 'node trade-journal/journal.js trade <id>' (these + invalidation + R courant + decroissance du /14) -> CONTINUER l'analyse routine-apres-routine, ne pas re-deriver de zero. Si le brief montre /14 en DECROISSANCE ou que l'invalidation loggee est touchee -> resserrer le SL ou sortir. TRAILING OBLIGATOIRE des >=1R: poser bybit_set_trailing_stop (SL natif continu qui protege le gagnant ENTRE les routines, comble l'angle mort 4h) -> ne jamais laisser un gagnant >=1R sans protection continue. TIMELINE (OBLIGATOIRE pour CHAQUE trade open/pending gere ce run): apres avoir statue (keep/trail/scale/exit/cancel), appeler 'node trade-journal/journal.js note' avec {id, mark (prix courant), upnl, decision:'keep|trail|scale_in|take_partial|reposition|cancel|exit', note (1-2 lignes: etat de la these + ce qui a ete fait), score:{components,gate} (le /14 RE-EVALUE maintenant -> on suit sa decroissance pendant la detention)}. Cela historise l'analyse du trade dans le temps (champ timeline + page trades/<id>.md). Sans note, journal.js report emet un warning (timeline trouee). ROTATION DE POSITION (exception, PAS un reflexe): UNIQUEMENT si on est PLEIN (4 positions ou cap 3 meme sens atteint) ET qu'un nouveau candidat a edge valide de conviction NETTEMENT superieure se presente -> evaluer SEULEMENT les positions DEJA EN GAIN (uPnL>0) dont la these s'est essoufflee ou qui ont deja parcouru l'essentiel de leur move (proche TP, momentum qui retombe): prendre le profit (bybit_take_partial ou close) pour liberer le slot et redeployer. REGLES DURES: JAMAIS cloturer une position PERDANTE pour tourner (laisser le SL gerer les perdants); ne PAS churner (garder par defaut); la rotation se justifie seulement par un gain a securiser + une opportunite clairement meilleure. Documenter la rotation dans le journal (review de la position fermee + rationale de la nouvelle). REFLEXION POST-TRADE (OBLIGATOIRE, pattern TradingAgents): pour CHAQUE trade CLOTURE depuis le dernier run (repere via reconcile.updated / sync / brief), ecrire une review en 3 questions via 'node trade-journal/journal.js set' (append au champ review, prefixe [<date> POST-TRADE]): (1) THESE JOUEE? le scenario anticipe s'est-il realise (meme si on a ete sorti)? distinguer these fausse / these juste mais sweep-out ou timing / these juste et capturee. (2) EXIT CONFORME? la sortie est-elle celle du plan (TP/SL/trailing) ou un accident (sweep, orphelin, gestion ratee)? comparer au bracket prevu. (3) LECON? si un pattern NOUVEAU emerge (pas deja dans LESSONS) -> l'ajouter a LESSONS.md, sinon noter 'rien de neuf, renforce une lecon existante'. C'est ce qui alimente LESSONS en continu (cout: 3 phrases). (2) SCAN: 'node trade-journal/scan.js' (19 paires) -> retiens les 3 MEILLEURS candidats par score, puis coin_analysis 1D+4H sur ces 3 via MCP tradingview-screener. REGIME MARCHE + ROUTAGE setup<->regime (TOP2): chaque opportunite du scan porte regime_d (regime ADX daily de la paire) ET regime_fit {fit:good|avoid|neutral|unknown, edge_R, note} = verdict backtest-backed (split 5a) du setup dans SON regime. ROUTAGE: regime_fit:good (S1 en trending/strong +0.35R, S2 en trending +0.30R [valide 10.06], S12 squeeze-break en trending +0.19R [valide 10.06 cross-TF 4H+1H], MR8 en range/trending +0.13-0.19R, S5 en range +0.31R) -> PRIVILEGIER ce candidat. regime_fit:avoid -> DE-PRIORISER/s'abstenir. CAS DURCIS EN SKIP DUR (valides sur 2 fenetres OOS + train coherent, 10.06): S1 en range (-0.055/-0.193R) et S2 en range (-0.08/-0.197R) = ne JAMAIS prendre, meme si le scan les surface. MR8 en strong reste avoid souple (train/test incoherents). neutral/unknown -> jugement normal (/14+gating). Le but: chasser activement le setup qui COLLE au regime live (STRONG_TREND -> S1 short-du-rebond ; TRENDING -> S1 ou S2 continuation ; RANGE -> S5/MR8 fades). market.regime (BTC daily ADX) reste le contexte macro: STRONG_TREND = prudence generale sur les fades. FUNDING S6/S9 = NON valides OOS (signal-only) -> NE PAS les trader, juste observer/logger. RISQUE AGREGE: 'journal.js exposure' renvoie risk_pct par sens + risk_warning -> si risk_warning present (risque agrege > seuil), NE PAS ajouter de position ce sens MEME si le cap en compte n'est pas atteint (anti-cluster correle). CAP TOTAL BOOK: total_risk_pct <=18% (les 2 sens cumules) en plus du 12%/sens -> si total_warning, ne plus RIEN ajouter (anti choppy bilateral). COMPTAGE = THESE: 1 trade laddered = 1 actif = 1 unite de risque (ses 3 rungs ne comptent PAS comme 3 trades, et ses rungs restants doivent toujours pouvoir filler). ANNULATION DYNAMIQUE (live_full 5/5): annuler le pending same-side le plus faible au fill MAIS JAMAIS les rungs restants d'un trade deja partiellement live (status open = entree en cours, pas un nouveau trade ; n'annuler QUE des theses pending a ZERO fill). Capacite reelle (cap 12%/sens): ~4-5 trades/sens en B (2.5%), ~2 en A+ (5%). (3) ZONES DESKTOP pour ces candidats: 'node scripts/tv-preflight.js'; si CDP up, pour chaque candidat: chart_set_symbol + chart_set_timeframe 240/D + data_get_pine_boxes {study_filter:Zeiierman, verbose:true} + data_get_pine_lines (Fib) + data_get_study_values (StochRSI/AI Supertrend/TEMA/AI Signal) + data_get_pine_labels (regime Trend Channels) -> mapping DESKTOP_INDICATORS.md; si CDP down -> fallback pivots screener (zones=screener_fallback). (4) DECISION ORIENTEE ACTION (objectif: SAISIR les opportunites, viser plusieurs trades/semaine; le no_trade n'est PAS l'option par defaut). Pour CHACUN des 3 candidats, PRENDRE le trade si: (a) setup a EDGE VALIDE = S1/S3/S5/MR4/MR8, PLUS S2 et S12 UNIQUEMENT si regime_fit:good (= paire en trending ; S2 +0.30R, S12 squeeze-break +0.19R cross-TF, valides OOS 10.06 ; S2 en range = SKIP DUR, S12 hors trending = ne pas prendre). Ignorer S4/S7/S8 (perdants OOS ; S8-en-strong = artefact train/test incoherent, ne pas re-tester), (b) REGLE R:R/GEOMETRIE (amendee approved 10.06): R:R>=2 jusqu'a TP2 pour les setups de TENDANCE (S1/S2/S3/S12) ; les MEAN-REVERSION (MR8/MR4/S5) sont EXEMPTES de R:R>=2 A CONDITION d'utiliser leur geometrie ATR validee OOS (MR8: SL 2.5xATR / TP ~2xATR + trailing ; S5/MR4: 1:1 SL 2xATR / TP 2xATR) -- un bracket MR ni R:R>=2 ni geometrie validee = INTERDIT (l'entre-deux comprime = cause du sweep-out HYPE -0.30R), (c) un niveau d'entree propre existe = zone Zeiierman alignee (PREFEREE, precision max) OU, A DEFAUT de zone proche, une structure ATR claire (SL=swing structure ou 1.5xATR, TP=2-3xATR ou 1:1 pour mean-reversion -- la facon EXACTE dont l'edge a ete valide OOS dans optimize.js) -> dans ce cas DEMI-taille B (confiance d'entree reduite, pas l'edge en moins). L'ABSENCE DE ZONE N'EST PLUS UN NO-TRADE (l'edge MR8/S5/MR4 ne requiert pas de zone, prouve OOS avec exits ATR). Le no-trade reste pour: pas de setup a edge valide, R:R<2, cap correlation, gating dur, breaker, quota. (d) GATING DUR passe = PAS de regime Trend Channels STRONG oppose ni flip AI Supertrend contraire imminent. Le score /14 sert UNIQUEMENT a DIMENSIONNER (pas a bloquer): >=9 -> pleine taille A+, 6-8 -> demi B, <6 mais (a)-(d) OK -> demi B prudente. TIMING 1H: chaque candidat du scan porte un champ h1 {rsi,dir,trend,macd,stochrsi} = contexte 1H pour le TIMING d'entree. Privilegie les entrees ou le 1H confirme le retournement (short si h1.dir=falling ou h1.macd=bear ; long si rising/bull) ; un 1H qui contredit fortement = attendre/reduire la taille. Le 1H affine timing + conviction, ce N'EST PAS un trigger de setup. Option: lire le Desktop en 1H (chart_set_timeframe 60) sur le candidat retenu pour affiner zone d'entree/SL fins. (5) EXECUTER chaque trade retenu dans la limite des garde-fous (max 5 positions LIVE (8 actifs live+pending ; BINDING = risque agrege <=12%/sens, pas le compte ; live plein -> annuler le pending same-side faible au fill), max 3 nouveaux/jour, cap correlation par sens, breaker): entree limit au bord de zone Zeiierman + SL au-dela. SL ANTI-SWEEP (finding the maintainer 10.06, cas HYPE SL 55.50 vs low 55.455): JAMAIS poser le SL PILE sur ou au-dessus du niveau evident (swing low/high, bord de zone, chiffre rond) = poche de liquidite, le marche balaie ces stops avant de s'inverser (mesure: ~150 sweeps de swing 12-barres en 6 mois detectes par S11). SL = au-dela des MECHES du niveau avec buffer >=0.3xATR. GATE PREFLIGHT OBLIGATOIRE AVANT DE POSER LE BRACKET (pattern OpenAlice/UTA, 11.06): 'node trade-journal/journal.js preflight {symbol,side,setup,entry,stop_loss,take_profits}' = UN SEUL appel qui agrege TOUS les garde-fous en un verdict ok:true(ALLOW)/ok:false(BLOCK): SL obligatoire + geometrie SL anti-sweep (floor par famille, ATR live) + R:R>=2 tendance + circuit breaker + quota 3/j + exposition agregee. ok:false -> NE PAS poser le bracket, lire blocks[] pour les raisons (il remplace les appels separes sl-check+exposure+risk, il les agrege). Il inclut sl-check (champ sl_check + suggested_sl si la geometrie casse -> utiliser le suggested_sl ou descendre l'entree, ou pour un MR poser la geometrie validee SL 2.5xATR/TP 2xATR, et RE-passer preflight). preflight est un gate DETERMINISTE qui empeche d'OUBLIER un check ; il ne remplace aucun seuil. GEOMETRIE = ECHEC DUR avec floor PAR FAMILLE (approved 10.06): dist SL < floor -> ok:false (MR8 >=2.5xATR, S5/MR4 >=2xATR, S1 >=1.5xATR, x0.85 tolerance ; famille inconnue 1xATR). Ne JAMAIS poser un bracket dont le sl-check est ok:false. TP ANTI-FRONT-RUN (miroir du SL, mining 10.06): les TP se placent 0.1-0.2xATR AVANT le niveau evident (jamais PILE sur un chiffre rond/zone -- cas S3 BTC: high 62950, TP1 63000 rate de 50pts = une nuit d'expo en plus). Geometrie complete: SL au-dela des meches + buffer, TP avant le niveau - retrait. Si le R:R-cible casse a cause du buffer: setup de TENDANCE -> DESCENDRE L'ENTREE dans la zone (meilleur prix) plutot que rogner le buffer, sinon passer ; setup MR -> poser la GEOMETRIE VALIDEE (SL 2.5xATR / TP ~2xATR, l'exemption R:R couvre ce cas), JAMAIS un SL comprime. Le sizing recalcule automatiquement (risque constant: SL plus loin = position plus petite, PAS plus de perte). Taille via 'node trade-journal/journal.js size' en passant le champ edge=<multiplicateur EDGE NET du setup: S5_fade_range 1.4, MR8_stochrsi_revert 1.2, S1_short_bounce 1.0, S2_short_continuation 0.8 (trending uniquement), S12_squeeze_break 0.8 (trending uniquement), MR4_bb_trendfilt 0.6, S3_long_oversold 0.6> (A2 Kelly-lite: S5/MR8 gardent 5%, edges marginaux MR4/S1/S3 risquent moins car les frais ont roge leur edge net), 'node skills/bybit/index.js bybit_place_limit_bracket' (ENTREE ECHELONNEE = DEFAUT POUR LES MR (valide OOS sprint #7, approved 10.06): pour MR8/MR4/S5, poser 3 TRANCHES limit independantes de 1/3 de la size chacune via 3 appels bybit_place_limit_bracket -- T1 au niveau d'entree normal, T2 = T1 -/+ 0.5xATR, T3 = T1 -/+ 1.0xATR (plus profond dans le sens favorable), chaque tranche avec SON bracket complet a la geometrie validee (SL 2.5xATR de SON entree, TP ~2xATR) et son sl-check (champ setup) -- risque TOTAL = budget normal (size/3 par tranche), si seule T1 fille seul 1/3 du risque est engage ; tagger entry_mode:laddered ET risk_usd:<budget total> dans journal.js log (1 seul trade au journal, size totale, entree=T1) -- risk_usd OBLIGATOIRE pour un ladder = risque total budgete (somme par rung), sinon exposure SURESTIME le risque du ladder de ~50% (size x distance T1->SL, T1 = rung le plus loin du SL) et bloque l'ajout trop tot. Les setups de TENDANCE S1 et S2 en trending/strong UNIQUEMENT utilisent AUSSI le laddered (valide OOS sprint #8 10.06, approved): pour un short T2/T3 = T1 +0.5/+1.0xATR (plus HAUT) = vendre plus haut dans la resistance sur l'extension du rebond (= le trade ASTER) ; OOS par regime S1 trending +1.10R strong +0.67R, S2 trending +0.74R strong +1.09R vs single-entry overfit ; EN RANGE S1/S2 = SKIP DUR (laddered negatif aussi) donc le laddered tendance s'applique UNIQUEMENT en trending/strong. S3/S12 gardent l'entree simple (laddered non teste sur ces signaux). EDGE non booste tant que le forward-test demo ne confirme pas (trade ASTER 10.06 = 1er datapoint live). ENTREE LIMIT/MAKER OBLIGATOIRE par defaut -- maker 0.02% vs taker 0.055% ; les edges minces MR4/S1 ne sont rentables qu'en maker, le market two-phase=taker les tue ; market reserve a une continuation qui exige entree immediate, rare) PUIS VERIFIER le bracket: 'node trade-journal/journal.js verify-bracket {symbol,side,size,stop_loss,take_profits}' -- si critical:true (position nue / SL oversize apres fill partiel / sens inverse), CORRIGER le SL a la taille reelle avant de continuer + notifier. Puis 'node trade-journal/journal.js log' (rationale: zones lues + zones=zeiierman|screener_fallback + setup + score/14 + tier + champ invalidation = la condition OBSERVABLE qui casse la these, ex. 4H close au-dela du SL/EMA OU RSI 4H repasse > 50 rising OU regime qui flippe -> relue a chaque routine via le brief). INSTRUMENTATION SCORING (OBLIGATOIRE a chaque log de decision, trade ET no_trade): ajouter au JSON un bloc score:{components:{zeiierman,rsi,macd,regime,supertrend,stochrsi,ai_signal,fib,adx,vwap,candle} = valeurs 0..max selon DESKTOP_INDICATORS.md (ne mettre QUE les composantes observees), gate:{regime_strong_opp:bool, supertrend_flip_opp:bool}, zones:'zeiierman'|'screener_fallback'}. Le CODE derive total/tier/rr/gate.passed (ne PAS les calculer toi-meme). Pour un no_trade, le champ hypo fournit deja entry/sl/tp pour le R:R. Sans bloc score, journal.js emet un warning (instrumentation incomplete). Pour TOUS les mean-reversion (MR8/S5/MR4): TP = la GEOMETRIE validee (~2xATR / 1:1 cible symetrique, bord oppose du range / EMA20 / VWAP), PAS une zone lointaine pour gonfler le R:R (l'exemption R:R rend ce bricolage inutile). no_trade UNIQUEMENT si aucun des 3 candidats ne remplit (a)-(d), ou breaker actif -> documenter la raison. SUIVI QUALITE (OBLIGATOIRE): pour TOUT no_trade qui a rejete un candidat PRECIS (setup avec des niveaux), AJOUTER OBLIGATOIREMENT dans le journal.js log un champ hypo:{symbol,side,entry,sl,tp} (les niveaux qu'on aurait pris) -- sans hypo, journal.js emet un warning 'SANS HYPO' et le refus n'est PAS mesurable. Omettable UNIQUEMENT si scanner=0 opportunite (rien a rejeter). hypo -> permet a notrade-eval.js de verifier plus tard si le refus etait JUSTE (aurait touche le SL) ou FAUX (aurait touche le TP). Le bot apprend ainsi de ses non-decisions. (6) 'node trade-journal/journal.js report' puis dashboard, notify si actionnable. Garde-fous NON negociables: DEMO only, SL obligatoire, R:R>=2 tendance / geometrie ATR validee MR (approved 10.06), max 3 trades/jour, max 5 positions LIVE (8 actifs live+pending ; BINDING = risque agrege <=12%/sens, pas le compte ; live plein -> annuler le pending same-side faible au fill), circuit breaker, cap correlation. Termine par le resume au format attendu."

# Allowlist SCOPEE (les gardes restent actives) : node (skills + journal + analyse),
# lecture/ecriture repo, screener ET desktop (zones Zeiierman) -- rien d'autre.
# Pas de shell destructif, pas de git, pas de mainnet. Headless via --allowedTools.
$tools = "Bash(node:*) Read Write Edit Glob Grep mcp__tradingview-screener__* mcp__tradingview-desktop__*"
# Mode MANUEL : prefixe le prompt -> source=manual, exempt du quota max-3/jour (the maintainer decide), garde-fous risque intacts.
# Un run manuel CONTRIBUE autant qu'un run auto (meme SOP + heartbeat + obsidian-sync, non gated ci-dessous).
# Inclusion : SEUL strategy MANUAL_TEST_* est exclu des stats/score-eval/slippage ; source:manual REEL compte.
if ($Manual) { $prompt = "*** RUN MANUEL (lance a la main par the maintainer). source=manual. Un run manuel APPORTE AUTANT A L'ANALYSE qu'un run auto : fais la SOP COMPLETE (reconcile, brief de chaque trade ouvert, note timeline, verify-bracket, trailing >=1R, scan + regime_fit, decision, obsidian, heartbeat) -> il faut faire AVANCER les trades en temps reel et capturer toute opportunite live. EXEMPTE du quota max-3-trades/jour (the maintainer decide) MAIS respecte TOUS les autres garde-fous (SL obligatoire, R:R>=2 tendance / geometrie ATR validee MR, max 5 positions LIVE (8 actifs live+pending ; BINDING = risque agrege <=12%/sens, pas le compte ; live plein -> annuler le pending same-side faible au fill), cap correlation, circuit breaker, DEMO only). Ajoute le champ source:manual dans CHAQUE 'journal.js log', prefixe le resume final par [MANUEL]. IMPORTANT ETIQUETAGE: un trade manuel REEL garde son VRAI setup (S1/S3/S5/MR4/MR8) + source:manual -> il COMPTE pleinement dans la perf/score-eval/slippage/suivi. N'utilise la strategy MANUAL_TEST_* QUE pour un test de plomberie SANS valeur d'analyse (ces seuls-la sont exclus des stats) -> NE PAS mal etiqueter un vrai trade en MANUAL_TEST. LABO 2-PISTES (10.06) : un trade manuel a SETUP CATALOGUE valide (S1/S2/MR8...) = piste PRODUCTION (compte dans la perf qui juge le systeme). Un trade manuel a GEOMETRIE NOUVELLE (deep accum, swing, contra-trend hors catalogue) = piste EXPERIMENT -> tagger track:experiment au log + sizer en tier D (data-mode, risque reduit ~0.75%) -> il ne pollue PAS la prod (stats.by_track et score-eval le separent) mais genere de la data. Un experiment prometteur -> /edge-sprint OOS -> cable (boucle ASTER->sprint#8). *** " + $prompt }
# #6 Completude de routine : on capture l'etat AVANT pour detecter un demi-echec silencieux.
$tradesFile = "$proj\trade-journal\trades.jsonl"
$beforeLines = 0; try { $beforeLines = (Get-Content $tradesFile -ErrorAction SilentlyContinue | Measure-Object -Line).Lines } catch {}

# D1 TIERING DE MODELE : Opus 4.8 (qualite de decision) par defaut ; mais si GESTION PURE
# (4/4 positions -> AUCUN nouveau trade possible), Sonnet suffit (KEEP/trail/note) = economie.
# Override global : $env:ROUTINE_MODEL. Mode manuel = toujours Opus (decision deliberee).
$model = if ($env:ROUTINE_MODEL) { $env:ROUTINE_MODEL } else { "claude-opus-4-8" }
if (-not $Manual -and -not $env:ROUTINE_MODEL) {
  try {
    $expo = node "$proj\trade-journal\journal.js" exposure | ConvertFrom-Json
    if ((-not $expo.can_add_long) -and (-not $expo.can_add_short)) { $model = "sonnet"; Add-Content -Path $log -Value "[TIERING] aucun nouveau trade possible (caps/risque) -> gestion pure -> Sonnet" }
  } catch {}
}
claude -p $prompt --model $model --permission-mode acceptEdits --allowedTools $tools *>> $log 2>&1
$claudeExit = $LASTEXITCODE

# Heartbeat (dead-man) : trace que la routine a tourne (post-execution) + ping HEALTHCHECK_PING_URL.
# Garanti meme si l'agent oublie de le faire -> le watchdog health-check.ps1 detecte un agent muet.
node "$proj\trade-journal\journal.js" heartbeat *>> $log 2>&1

# Fiche Obsidian : met a jour le bloc "Etat live (auto-routine)" depuis le journal (deterministe,
# pas de LLM = zero drift). Garanti a chaque routine. No-op gracieux si la note est absente.

# Notes de trades Obsidian (deuxieme cerveau) : 1 note datee par trade depuis trades.jsonl
# (frontmatter -> vues Bases ; bloc NOTES-MANUELLES preserve). Idempotent, no-op si vault absent.

# #6 CHECK COMPLETUDE : une routine COMPLETE logge TOUJOURS au moins 1 decision (trade ou no_trade
# = +1 ligne). Si claude a echoue (exit!=0) OU aucune nouvelle ligne -> DEMI-ECHEC SILENCIEUX -> alerte.
# (Le heartbeat seul ne capte que le silence TOTAL, pas un cycle a moitie fait.)
$afterLines = 0; try { $afterLines = (Get-Content $tradesFile -ErrorAction SilentlyContinue | Measure-Object -Line).Lines } catch {}
$complete = ($claudeExit -eq 0 -and $afterLines -gt $beforeLines)
if (-not $Manual -and -not $complete) {
  $why = if ($claudeExit -ne 0) { "claude exit=$claudeExit" } else { "aucune nouvelle entree journal (pas de decision/no-trade loggee)" }
  Add-Content -Path $log -Value "[COMPLETUDE] ROUTINE INCOMPLETE: $why"
  node "$proj\trade-journal\notify.js" "ROUTINE INCOMPLETE ($src) -- $why. Cycle a moitie fait, verifier $log" *>> $log 2>&1
  # Persiste l'incompletude dans heartbeat.json -> le watchdog detecte 'vivant mais incomplet' meme si
  # l'alerte Telegram ci-dessus rate (transitoire). Comble le gap : heartbeat seul = faux 'OK'.
  node "$proj\trade-journal\journal.js" routine-status "{`"complete`":false,`"reason`":`"$why`"}" *>> $log 2>&1
} else {
  node "$proj\trade-journal\journal.js" routine-status '{"complete":true}' *>> $log 2>&1
}

Write-Output "Routine ($src) terminee -> $log"
